mapper.select:
SELECT ROW_NUMBER() OVER ( PARTITION BY YYYYMM, SEL_CODE, SITE, 모델명 ORDER BY 생성시각 ) AS ROW_SEQ, YYYYMM, SEL_CODE, SITE AS SITE_ORG, CASE WHEN SITE = 'HQ' THEN '본사' WHEN SITE = 'VN' THEN 'VINA' END AS SITE, CASE WHEN 모델명 LIKE '%D' THEN '개발' ELSE '양산' END AS 구분, 모델명, RMA_IN, RMA_OUT, 생성자, 생성시각 FROM DOI_RMA_INOUT WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
ORDER BY 모델명

mapper.update:
;WITH T AS (
   SELECT
       ROW_NUMBER() OVER (
           PARTITION BY YYYYMM, SEL_CODE, SITE, 모델명
           ORDER BY 생성시각
       ) AS ROW_SEQ,
       *
   FROM DOI_RMA_INOUT
   WHERE YYYYMM = #{yyyymm}
     AND SEL_CODE = #{selCode}
     AND SITE = #{siteOrg}
     AND 모델명 = #{모델명}
   )
   UPDATE T
   SET 
       RMA_IN  = #{rmaIn},
       RMA_OUT = #{rmaOut},
       생성자   = #{생성자},
       생성시각 = SYSDATETIME()
   WHERE ROW_SEQ = #{rowSeq}

mapper.delete:
WITH T AS (
    SELECT
        ROW_NUMBER() OVER (
            PARTITION BY YYYYMM, SEL_CODE, SITE, 모델명
            ORDER BY 생성시각
        ) AS ROW_SEQ,
        *
    FROM DOI_RMA_INOUT
    WHERE YYYYMM = #{yyyymm}
    AND SEL_CODE = #{selCode}
    AND SITE = #{siteOrg}
    AND 모델명 = #{모델명}
)
DELETE FROM T
WHERE ROW_SEQ = #{rowSeq}

mapper.select:
SELECT MODEL, SPEC, INCH FROM DOI_MODEL_MAST WHERE 1=1 AND YYYYMM = '202507'
AND SITE = #{site}
AND MODEL = #{model}
ORDER BY MODEL
